const http = require('http');
http.get('http://localhost:3000/token?room=myroom&identity=myuser', (res) => {
  let data = '';
  res.on('data', chunk => data += chunk);
  res.on('end', () => {
    const token = JSON.parse(data).token;
    const req = http.request('http://localhost:3000/refresh', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' }
    }, (res2) => {
      let data2 = '';
      res2.on('data', chunk => data2 += chunk);
      res2.on('end', () => {
        console.log(data2);
      });
    });
    req.write(JSON.stringify({ token }));
    req.end();
  });
});
"

